import React, { useState, useEffect, useRef } from 'react';
import { useParams, Link } from 'react-router-dom';
import axios from 'axios';
import html2canvas from 'html2canvas';

const TemplateEditor = () => {
  const { id } = useParams();
  const [template, setTemplate] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [cellContents, setCellContents] = useState({});
  const editorRef = useRef(null);

  // 获取模板数据
  useEffect(() => {
    const fetchTemplate = async () => {
      try {
        const response = await axios.get(`/api/template/${id}`);
        setTemplate(response.data);

        // 初始化格子内容
        const initialContents = {};
        response.data.cells.forEach(cell => {
          const cellKey = `${cell.day}-${cell.index}`;
          initialContents[cellKey] = '';
        });
        setCellContents(initialContents);

        setLoading(false);
      } catch (err) {
        setError('获取模板失败');
        setLoading(false);
      }
    };

    fetchTemplate();
  }, [id]);

  // 更新格子内容
  const handleCellChange = (cellKey, value) => {
    setCellContents(prev => ({
      ...prev,
      [cellKey]: value
    }));
  };

  // 导出为图片
  const handleExport = async () => {
    if (!editorRef.current) return;

    try {
      // 临时保存输入框的值到textContent，确保导出时显示内容
      const inputs = editorRef.current.querySelectorAll('input');
      const originalValues = {};

      inputs.forEach(input => {
        originalValues[input.id] = input.value;
        // 确保输入框有值才设置textContent
        if (input.value) {
          input.textContent = input.value;
        }
      });

      const canvas = await html2canvas(editorRef.current, {
        backgroundColor: null,
        scale: 2, // 提高导出图片质量
        logging: false,
        useCORS: true, // 允许跨域图片
        allowTaint: true,
        onclone: (clonedDoc) => {
          // 在克隆的文档中确保样式正确
          const clonedEditor = clonedDoc.querySelector('.template-editor');
          if (clonedEditor) {
            const clonedInputs = clonedEditor.querySelectorAll('input');
            clonedInputs.forEach(input => {
              input.style.backgroundColor = 'transparent';
              input.style.border = 'none';
              input.style.color = '#000';
              input.style.fontSize = '14px';
              input.style.fontFamily = 'Arial, sans-serif';
              input.style.textAlign = 'center';
              input.style.padding = '5px';
              input.style.display = 'flex';
              input.style.alignItems = 'center';
              input.style.justifyContent = 'center';
            });
          }
        }
      });

      // 创建下载链接
      const link = document.createElement('a');
      link.download = `schedule-${Date.now()}.png`;
      link.href = canvas.toDataURL('image/png');
      link.click();
    } catch (err) {
      console.error('导出错误:', err);
      setError('导出失败');
    }
  };

  if (loading) {
    return <div className="loading">加载中...</div>;
  }

  if (error) {
    return <div className="error">{error}</div>;
  }

  if (!template) {
    return <div className="error">模板不存在</div>;
  }

  return (
    <div className="card">
      <div className="toolbar">
        <Link to="/" className="button button-secondary">
          返回列表
        </Link>
        <button 
          className="button button-success"
          onClick={handleExport}
        >
          导出图片
        </button>
      </div>

      <div 
        ref={editorRef}
        className="template-editor"
      >
        <img 
          src={`http://localhost:3001${template.image}`} 
          alt="模板" 
        />
        {template.cells.map(cell => {
          const cellKey = `${cell.day}-${cell.index}`;
          return (
            <div
              key={cellKey}
              className="cell"
              style={{
                left: cell.x,
                top: cell.y,
                width: cell.width,
                height: cell.height
              }}
            >
              <input
                type="text"
                value={cellContents[cellKey] || ''}
                onChange={(e) => handleCellChange(cellKey, e.target.value)}
                placeholder="输入课程"
              />
            </div>
          );
        })}
      </div>
    </div>
  );
};

export default TemplateEditor;
